content.content:
       19: #[derive(Debug, Clone, PartialEq, Eq)]
       20: pub enum DotDirection {
       21:     /// No dots: just the revision itself.
       22:     None,
       23:     /// `x..` — ancestors (x at top, older below).
       24:     Ancestors,
       25:     /// `..x` — descendants (newer above, x at bottom).
       26:     Descendants,
       27:     /// `..x..` — both directions, x in the middle.
       28:     Both,
       29: }
       30: 
       31: /// Result of parsing positional `..` notation.
       32: #[derive(Debug, Clone, PartialEq, Eq)]
       33: pub struct DotSpec {
       34:     /// The bare revision (without `..`).
       35:     pub rev: String,
       36:     /// Which direction(s) the dots indicate.
       37:     pub direction: DotDirection,
       38:     /// Count per dotted side (x is not counted).
       39:     pub count: usize,
       40: }
       41: 
       42: /// Parse a positional REV string for `..` notation.
       43: ///
       44: /// Returns the bare revision, direction, and default count (0).
       45: /// Count is set separately from the second positional arg.
       46: pub fn parse_dot_rev(rev: &str) -> DotSpec {
       47:     if let Some(inner) = rev.strip_prefix("..").and_then(|s| s.strip_suffix("..")) {
       48:         DotSpec {
       49:             rev: inner.to_string(),
       50:             direction: DotDirection::Both,
       51:             count: 0,
       52:         }
       53:     } else if let Some(inner) = rev.strip_prefix("..") {
       54:         DotSpec {
       55:             rev: inner.to_string(),
       56:             direction: DotDirection::Descendants,
       57:             count: 0,
       58:         }
       59:     } else if let Some(inner) = rev.strip_suffix("..") {
       60:         DotSpec {
       61:             rev: inner.to_string(),
       62:             direction: DotDirection::Ancestors,
       63:             count: 0,
       64:         }
       65:     } else {
       66:         DotSpec {
       67:             rev: rev.to_string(),
       68:             direction: DotDirection::None,
       69:             count: 0,
       70:         }
       71:     }
       72: }
       73: 
       74: /// Resolve effective revision, limit, and whether results need reversing
       75: /// from positional args combined with named flags.
       76: ///
       77: /// Named flags (`-r`, `-l`) take precedence over positional args.
       78: pub struct ResolvedArgs {
       79:     /// The jj revset string to evaluate.
       80:     pub revset: String,
       81:     /// Maximum number of commits to return (None = unlimited).
       82:     pub limit: Option<usize>,
       83:     /// Whether to reverse the results (for descendants/both).
       84:     pub reverse: bool,
       85:     /// For `..x..`, the count per side.
       86:     pub both_count: Option<usize>,
       87: }
       88: 
       89: /// Resolve positional `..` args with named flag overrides.
       90: ///
       91: /// - `pos_rev`: first positional arg (may contain `..`)
       92: /// - `pos_count`: second positional arg
       93: /// - `flag_rev`: `-r` flag value (if different from default)
       94: /// - `flag_limit`: `-l` flag value
       95: /// - `default_rev`: the default revision (e.g. "@")
       96: pub fn resolve_dot_args(
       97:     pos_rev: Option<&str>,
       98:     pos_count: Option<usize>,
       99:     flag_rev: &str,
      100:     flag_limit: Option<usize>,
      101:     default_rev: &str,
      102: ) -> ResolvedArgs {
      103:     // If named flags were explicitly set, they take full precedence
      104:     let flag_rev_set = flag_rev != default_rev;
      105:     let flag_limit_set = flag_limit.is_some();
      106: 
      107:     if flag_rev_set || (flag_limit_set && pos_rev.is_none()) {
      108:         return ResolvedArgs {
      109:             revset: flag_rev.to_string(),
      110:             limit: flag_limit,
      111:             reverse: false,
      112:             both_count: None,
      113:         };
      114:     }
      115: 
      116:     // Use positional args
      117:     let rev_str = pos_rev.unwrap_or(default_rev);
      118:     let mut spec = parse_dot_rev(rev_str);
      119: 
      120:     // If there's a positional count, set it
      121:     if let Some(c) = pos_count {
      122:         spec.count = c;
      123:     }
      124: 
      125:     // Named limit overrides positional count
      126:     if flag_limit_set {
      127:         spec.count = flag_limit.unwrap();
      128:     }
      129: 
      130:     match spec.direction {
      131:         DotDirection::None => {
      132:             if spec.count > 0 {
      133:                 // bare `x 5` → `x.. 5` (ancestors)
      134:                 ResolvedArgs {
      135:                     revset: format!("::{}", spec.rev),
      136:                     limit: Some(spec.count + 1), // +1 for x itself
      137:                     reverse: false,
      138:                     both_count: None,
      139:                 }
      140:             } else {
      141:                 ResolvedArgs {
      142:                     revset: spec.rev,
      143:                     limit: Some(1),
      144:                     reverse: false,
      145:                     both_count: None,
      146:                 }
      147:             }
      148:         }
      149:         DotDirection::Ancestors => {
      150:             if spec.count > 0 {
      151:                 ResolvedArgs {
      152:                     revset: format!("::{}", spec.rev),
      153:                     limit: Some(spec.count + 1),
      154:                     reverse: false,
      155:                     both_count: None,
      156:                 }
      157:             } else {
      158:                 ResolvedArgs {
      159:                     revset: format!("::{}", spec.rev),
      160:                     limit: None,
      161:                     reverse: false,
      162:                     both_count: None,
      163:                 }
      164:             }
      165:         }
      166:         DotDirection::Descendants => {
      167:             if spec.count > 0 {
      168:                 ResolvedArgs {
      169:                     revset: format!("{}::", spec.rev),
      170:                     limit: Some(spec.count + 1),
      171:                     reverse: true,
      172:                     both_count: None,
      173:                 }
      174:             } else {
      175:                 ResolvedArgs {
      176:                     revset: format!("{}::", spec.rev),
      177:                     limit: None,
      178:                     reverse: true,
      179:                     both_count: None,
      180:                 }
      181:             }
      182:         }
      183:         DotDirection::Both => ResolvedArgs {
      184:             revset: format!("::{}|{}::", spec.rev, spec.rev),
      185:             limit: None,
      186:             reverse: false,
      187:             both_count: Some(spec.count),
      188:         },
