183→/// The child re-enters `main()`, parses `--exec`, and `finalize()` routes
184→/// it to `finalize_exec()` where the actual work happens.
185→fn daemonize(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
186→    log_msg(
