use std::io::Write;
use std::path::{Path, PathBuf};
use std::process::Stdio;

use clap::Args;

#[derive(Args, Debug)]
pub struct FinalizeArgs {
    /// Path to jj repo
    #[arg(long, default_value = ".")]
    pub repo: PathBuf,

    /// Source revision to squash
    #[arg(long, default_value = "@")]
    pub source: String,

    /// Target revision to squash into
    #[arg(long, default_value = "@-")]
    pub target: String,

    /// Seconds to wait before squashing
    #[arg(long, default_value_t = 1.0)]
    pub delay: f64,

    /// Push after squashing
    #[arg(long)]
    pub push: bool,

    /// Log file path (default: /tmp/vc-x1-finalize-<timestamp-millis>.log)
    #[arg(long)]
    pub log: Option<PathBuf>,

    /// Run in foreground instead of daemonizing
    #[arg(long)]
    pub foreground: bool,

    /// Internal: run exec path (used by daemonize)
    #[arg(long, hide = true)]
    pub exec: bool,
}

#[derive(Debug)]
pub struct FinalizeOpts {
    pub repo: PathBuf,
    pub source: String,
    pub target: String,
    pub delay_secs: f64,
    pub push: bool,
    pub log: PathBuf,
    pub foreground: bool,
    pub exec: bool,
}

impl FinalizeArgs {
    pub fn into_opts(self) -> FinalizeOpts {
        let log = self.log.unwrap_or_else(|| {
            PathBuf::from(format!(
                "/tmp/vc-x1-finalize-{}.log",
                std::time::SystemTime::now()
                    .duration_since(std::time::UNIX_EPOCH)
                    .unwrap_or_default()
                    .as_millis()
            ))
        });
        FinalizeOpts {
            repo: self.repo,
            source: self.source,
            target: self.target,
            delay_secs: self.delay,
            push: self.push,
            log,
            foreground: self.foreground,
            exec: self.exec,
        }
    }
}

pub fn log_msg(log: &Path, msg: &str) {
    let nanos = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_nanos();
    let pid = std::process::id();
    let line = format!("[{nanos}] pid={pid} {msg}\n");
    if let Ok(mut f) = std::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(log)
    {
        let _ = f.write_all(line.as_bytes());
    }
}

fn run_jj(args: &[&str], log: &Path) -> Result<(), Box<dyn std::error::Error>> {
