    fn finalize_all_opts() {
        let cli = parse(&[
            "vc-x1",
            "finalize",
            "--repo",
            ".claude",
            "--source",
            "@",
            "--target",
            "@-",
            "--bookmark",
            "dev-0.14.0",
            "--delay",
            "2.5",
            "--push",
