        if let Commands::Finalize(args) = cli.command {
            assert_eq!(args.repo, PathBuf::from(".claude"));
            assert_eq!(args.source, "@");
            assert_eq!(args.target, "@-");
            assert_eq!(args.bookmark, "dev-0.14.0");
            assert_eq!(args.delay, 2.5);
