 88→fn print_both_chid(
 89→    repo: &std::sync::Arc<jj_lib::repo::ReadonlyRepo>,
 90→    root_commit_id: &jj_lib::backend::CommitId,
 91→    args: &ChidArgs,
 92→    both_count: usize,
 93→) -> Result<(), Box<dyn std::error::Error>> {
 94→    // We need to find the anchor revision to split ancestors/descendants.
 95→    // Re-resolve just the bare rev to find its commit ID.
 96→    let bare_rev = args.pos_rev.as_deref().unwrap_or("@");
 97→    let spec = common::parse_dot_rev(bare_rev);
 98→    let (workspace, repo2) = common::load_repo(&args.repo)?;
 99→    let anchor_ids = common::resolve_revset(&workspace, &repo2, &spec.rev)?;
100→    if anchor_ids.is_empty() {
101→        return Err(format!("no commit found for revision '{}'", spec.rev).into());
102→    }
103→    let anchor_id = &anchor_ids[0];
104→
105→    // Resolve ancestors (::x) and descendants (x::) separately
106→    let ancestor_ids = common::resolve_revset(&workspace, repo, &format!("::{}", spec.rev))?;
107→    let descendant_ids = common::resolve_revset(&workspace, repo, &format!("{}::", spec.rev))?;
108→
109→    // Descendants (newest first from jj), excluding anchor
110→    let mut desc_lines: Vec<String> = Vec::new();
111→    for commit_id in &descendant_ids {
112→        if *commit_id == *root_commit_id || *commit_id == *anchor_id {
113→            continue;
114→        }
115→        let commit = repo.store().get_commit(commit_id)?;
116→        let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
117→        let change_short = &change_hex[..change_hex.len().min(12)];
118→        desc_lines.push(change_short.to_string());
119→    }
120→    if both_count > 0 {
121→        // Take the last `both_count` (closest to anchor), keep newest-first order
122→        let start = desc_lines.len().saturating_sub(both_count);
123→        desc_lines = desc_lines[start..].to_vec();
124→    } else {
125→        desc_lines.clear();
126→    }
127→
128→    // Anchor
129→    let anchor_commit = repo.store().get_commit(anchor_id)?;
130→    let anchor_hex = encode_reverse_hex(anchor_commit.change_id().as_bytes());
131→    let anchor_short = &anchor_hex[..anchor_hex.len().min(12)];
132→
133→    // Ancestors (newest first from jj), excluding anchor
134→    let mut anc_lines: Vec<String> = Vec::new();
135→    if both_count > 0 {
136→        let mut count = 0;
137→        for commit_id in &ancestor_ids {
138→            if *commit_id == *root_commit_id || *commit_id == *anchor_id {
139→                continue;
140→            }
141→            let commit = repo.store().get_commit(commit_id)?;
142→            let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
143→            let change_short = &change_hex[..change_hex.len().min(12)];
144→            anc_lines.push(change_short.to_string());
145→            count += 1;
146→            if count >= both_count {
147→                break;
148→            }
149→        }
150→    }
151→
152→    // Print: descendants (oldest first), then anchor, then ancestors (newest first)
153→    for line in &desc_lines {
154→        println!("{line}");
155→    }
156→    println!("{anchor_short}");
157→    for line in &anc_lines {
158→        println!("{line}");
159→    }
160→
161→    Ok(())
162→}
